SELECT "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Pancreatic' AND "Type of combination" = 'ICI+Chemoradiotherapy';

SELECT "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Multiple Myeloma' AND "Type of combination" = 'ICI+Chemo';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Treatment regimen"
FROM clinical_trials
WHERE "Trial phase" = 'Phase 3' AND "Cancer type" = 'Bladder' AND "Name of ICI" = 'PD1' AND "Monotherapy/combination" = 'Monotherapy';

SELECT "Treatment regimen"
FROM clinical_trials
WHERE "Trial phase" = 'Phase 2' AND "Cancer type" = 'Breast' AND ("Name of ICI" = 'PD1' OR "Name of ICI" = 'CTLA-4') AND "Monotherapy/combination" = 'Monotherapy';

SELECT "Treatment regimen"
FROM clinical_trials
WHERE "Trial phase" = 'Phase 3' AND "Monotherapy/combination" = 'Combination' AND "Name of ICI" = 'PD1' AND "Cancer type" = 'Multiple Myeloma';

SELECT "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Hepatocellular' AND "Type of combination" = 'ICI+Chemo';

SELECT "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Hepatocellular carcinoma' AND "Type of combination" = 'ICI+Anti-VEGF';

SELECT "Treatment regimen"
FROM clinical_trials
WHERE "Trial phase" = 'Phase 3' AND "Monotherapy/combination" = 'Combination' AND "Cancer type" = 'Hodgkin Lymphoma';

SELECT "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Melanoma' AND "Monotherapy/combination" = 'Combination' AND "Treatment regimen" LIKE '%immunotherapy%' AND "Treatment regimen" LIKE '%chemotherapy%' AND "Treatment regimen" LIKE '%anti-VEGF%';

SELECT "Primary endpoint"
FROM clinical_trials
WHERE "Year" = 2018 AND "Cancer type" = 'Renal cell' AND "Type of combination" = 'ICI+Chemo';

SELECT "Treatment regimen"
FROM clinical_trials
WHERE "Trial phase" = 'Phase 3' AND ("Cancer type" = 'Renal cell' OR "Cancer type" = 'Hodgkin Lymphoma') AND "Monotherapy/combination" = 'Combination' AND "Class of ICI" = 'PD-L1' AND "Is PD-L1 positivity inclusion criteria" = 'Yes';
